logger = logging.getLogger()
logger.setLevel(os.getenv("LOG_LEVEL", "INFO").upper())

s3 = boto3.client("s3")
sns = boto3.client("sns")

OUTPUT_BUCKET = os.getenv("OUTPUT_BUCKET", "")
OUTPUT_PREFIX = os.getenv("OUTPUT_PREFIX", "processed/")
SNS_TOPIC_ARN = os.getenv("SNS_TOPIC_ARN", "")
TAG_PROCESSED = os.getenv("TAG_PROCESSED", "true")


def lambda_handler(event, context):
    logger.info("Received event: %s", json.dumps(event))

    results = []
    records = event.get("Records", [])

    for record in records:
        try:
            result = process_record(record, context)
            results.append({"status": "success", "result": result})
        except Exception as exc:
            error_payload = {
                "error": str(exc),
                "traceback": traceback.format_exc(),
                "record": record,
                "request_id": getattr(context, "aws_request_id", None),
                "timestamp": datetime.now(timezone.utc).isoformat()
            }
            logger.error("Failed processing record: %s", json.dumps(error_payload))
            publish_notification(
                subject="Image Processing Failed",
                message=error_payload
            )
            results.append({"status": "error", "error": str(exc)})

    response = {
        "processed_records": len(records),
        "results": results
    }
    logger.info("Lambda completed: %s", json.dumps(response))
    return response


def process_record(record, context):
    bucket = record["s3"]["bucket"]["name"]
    key = unquote_plus(record["s3"]["object"]["key"])

    logger.info("Processing s3://%s/%s", bucket, key)

    source_bytes = read_s3_object(bucket, key)
    processed_bytes, metadata = process_image(source_bytes, key)

    destination_bucket = OUTPUT_BUCKET or bucket
    destination_key = build_output_key(key)

    write_s3_object(
        destination_bucket,
        destination_key,
        processed_bytes,
        metadata=metadata
    )

    tag_source_object(bucket, key, {"processed": TAG_PROCESSED})

    payload = {
        "status": "processed",
        "source_bucket": bucket,
        "source_key": key,
        "destination_bucket": destination_bucket,
        "destination_key": destination_key,
        "size_bytes": len(processed_bytes),
        "metadata": metadata,
        "request_id": getattr(context, "aws_request_id", None),
        "timestamp": datetime.now(timezone.utc).isoformat()
    }

    publish_notification(
        subject="Image Processed",
        message=payload
    )

    logger.info("Successfully processed s3://%s/%s to s3://%s/%s",
                bucket, key, destination_bucket, destination_key)

    return payload


def read_s3_object(bucket, key):
    try:
        response = s3.get_object(Bucket=bucket, Key=key)
        return response["Body"].read()
    except ClientError:
        logger.exception("Error reading S3 object s3://%s/%s", bucket, key)
        raise


def write_s3_object(bucket, key, body, metadata=None):
    try:
        content_type = guess_content_type(key)
        put_kwargs = {
            "Bucket": bucket,
            "Key": key,
            "Body": body,
            "ContentType": content_type
        }
        if metadata:
            put_kwargs["Metadata"] = {str(k): str(v) for k, v in metadata.items()}
        s3.put_object(**put_kwargs)
    except ClientError:
        logger.exception("Error writing S3 object s3://%s/%s", bucket, key)
        raise


def tag_source_object(bucket, key, tags):
    try:
        tag_set = [{"Key": str(k), "Value": str(v)} for k, v in tags.items()]
        s3.put_object_tagging(
            Bucket=bucket,
            Key=key,
            Tagging={"TagSet": tag_set}
        )
    except ClientError:
        logger.exception("Error tagging S3 object s3://%s/%s", bucket, key)
        raise


def process_image(image_bytes, key):
    metadata = {
        "processed": "true",
        "original_filename": os.path.basename(key),
        "processed_at": datetime.now(timezone.utc).isoformat()
    }
    return image_bytes, metadata


def build_output_key(source_key):
    base_name = os.path.basename(source_key)
    prefix = OUTPUT_PREFIX.strip("/")
    if prefix:
        return f"{prefix}/{base_name}"
    return base_name


def publish_notification(subject, message):
    if not SNS_TOPIC_ARN:
        logger.warning("SNS_TOPIC_ARN not set; skipping notification")
        return

    try:
        sns.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject=subject[:100],
            Message=json.dumps(message, default=str)
        )
    except ClientError:
        logger.exception("Error publishing SNS notification")
        raise


def guess_content_type(key):
    lower = key.lower()
    if lower.endswith(".jpg") or lower.endswith(".jpeg"):
        return "image/jpeg"
    if lower.endswith(".png"):
        return "image/png"
    if lower.endswith(".gif"):
        return "image/gif"
    if lower.endswith(".webp"):
        return "image/webp"
    if lower.endswith(".bmp"):
        return "image/bmp"
    if lower.endswith(".tiff") or lower.endswith(".tif"):
        return "image/tiff"
    return "application/octet-stream"